var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고모님이…… 할아버님이라고요?","JPN":"叔母様が……お祖父様ですって？","ENG":"Y-you’re... Grandfather?","TWN":"姑姑……是爺爺？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"말했었잖니, 지아야.","JPN":"言ったじゃないか、ユイ。","ENG":"Didn’t I tell you already, Jia?","TWN":"我不是跟你說嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"조만간 그 병실에서 일어나 쌩쌩하게 걸어 다닐 거라고.","JPN":"近いうちにあの病室を出て、元気に歩けるようになると。","ENG":"I’ll soon get better and walk out of this place.","TWN":"爺爺很快就會康復出院的。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 말……. 할아버님께서 종종 하시던…….","JPN":"その言葉……お祖父様が度々話していた……","ENG":"That’s... what Grandfather used to say...","TWN":"那句話……爺爺常掛在嘴邊……"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"설마, 정말 할아버님……?","JPN":"まさか、本当にお祖父様……？","ENG":"A-are you really Grandfather...?","TWN":"難道你真的是爺爺……？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"속지 마세요, 리더. 단순한 성문 변조기에 불과합니다.","JPN":"騙されないでください、リーダー。単なるボイスチェンジャーにすぎません。","ENG":"Don’t be fooled, Leader. She’s just using a voice modulator.","TWN":"老大，你別上當，那不過就是變聲器而已！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"저 자는 회장이 아니에요. 음성으로 혼란을 야기하는 건 흔한 속임수예요.","JPN":"あれは会長ではありません。音声で惑わすのはよくあるトリックです。","ENG":"She’s not the President. It’s another one of her tricks to cause confusion.","TWN":"她不是會長！利用聲音來引起混亂是常見的詐騙手法。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"초원이 말이 맞아! 회장님은 죽은 지 한참 지났잖아!","JPN":"ナオちゃんの言うとおりだよ！　会長はずっと昔に亡くなってるじゃん！","ENG":"Chowon’s right! The President passed away a long time ago!","TWN":"初源說得沒錯！會長都已經過世這麼久了！"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그렇다, 대장. 아무리 그리워도 죽은 사람은 두 번 다시 돌아오지 않아.","JPN":"そのとおりだ、隊長。どんなに恋しくても、死んだ人間は二度と戻らない。","ENG":"She’s right, Cap. The dead don’t come back to life, no matter how much you miss them.","TWN":"沒錯，隊長。我知道你很想念會長，但死人是不會復活的。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"덜떨어진 머저리들. 네놈들이 모르는 건 세상에 없는 줄 아나?","JPN":"アルファトリックス・イノベーションは間抜けどもの寄せ集めかしら。\\nあんたたちが知らないことはこの世にないとでも？","ENG":"Fools! You think you know everything there is to know about this world?","TWN":"愚昧的傢伙們！你們不知道，不代表就不存在於這個世界上。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"나는 회장의 생전 기억과 경험을 전부 이식했다.","JPN":"この体には会長の生前の記憶と経験をすべて移植した。","ENG":"I have all of my father’s memories and experiences implanted in my head.","TWN":"我移植了會長生前的全部記憶和經驗。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"워낙 분량이 방대해서 아직도 완전히 정착하진 않았지만…….","JPN":"あまりにも量が膨大で、まだ完全に定着していないけど……","ENG":"Although it hasn’t fully set in as it is a vast amount of data...","TWN":"不過因為量有點龐大，所以還沒完全載入……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"기억은 인간을 구분하는 중요한 요소이니, 나도 우리 아빠를…….","JPN":"記憶は人間を区分する重要な要素だから、私も父さんを……","ENG":"Since memory is a core part of what distinguishes a human being... it's not strange to claim...","TWN":"記憶是分辨人的其中一個要素，因此我以爸爸……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아니, 죽은 알파트릭스의 회장을 자처해도 이상하지 않지.","JPN":"いや、亡きアルファトリックスの会長を自任してもおかしくないわ。","ENG":"That I am still my father, no, the late President of Alphatrix.","TWN":"不對，我以死去的阿爾法崔克斯會長自居，一點也不奇怪。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"TWN":"　　"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"회장은 네게 자기도 어릴 적 부모를 잃었다고 말했지?","JPN":"会長はあんたに自分も幼い頃両親を亡くしたと言ったわよね？","ENG":"The President told you that he lost his parents at an early age, didn’t he?","TWN":"會長是不是跟你說過，他和你一樣從小便失去父母？"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"회장은 두려움에 겨워 기억을 묻어 뒀지만, 나는 알 수 있어.","JPN":"会長は恐怖に耐えきれず記憶を心の奥底にしまっていたけど、\\n私にはわかるわ。","ENG":"Although he may have blocked out that memory, I still remember it.","TWN":"雖然會長因為太害怕而將這段記憶埋才起來，但我還是可以知道。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};